/**
 * XUS NEURAL PREPARER v2.1
 */
const items = $input.all();
const result = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  if (!item.binary || !item.binary.data) continue;
  const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');
  const base64Data = buffer.toString('base64');
  let telegramData = {};
  try { telegramData = $("Telegram Trigger").first().json; } catch (e) {}
  result.push({
    json: {
      audioBase64: base64Data,
      mimeType: 'audio/ogg',
      chatId: telegramData?.message?.chat?.id || "-1003688744736",
      messageId: telegramData?.message?.message_id || ""
    }
  });
}
return result;

/**
 * XUS AUDIO PROCESSOR v1.0 — Telegram
 */
const input = $input.first().json;
let transcription = "";
try {
  if (input.candidates && input.candidates[0]?.content?.parts) {
    transcription = input.candidates[0].content.parts.map(part => part.text || '').join(' ').trim();
  }
} catch (e) { transcription = "ERROR_TRANSCRIPCION"; }

if (!transcription || transcription === "ERROR_TRANSCRIPCION" || transcription.length < 2) {
  transcription = "No pude entender el audio";
}

let telegramData = null;
try {
  const allItems = $("Telegram Trigger").all();
  if (allItems.length > 0) telegramData = allItems[0].json;
} catch (e) {}

const chatId = telegramData?.message?.chat?.id || "-1003688744736";

return {
  json: {
    message: {
      text: transcription,
      chat: { id: chatId },
      message_id: telegramData?.message?.message_id || "",
      from: telegramData?.message?.from || {}
    },
    isFromAudio: true,
    originalTranscription: transcription,
    timestamp: new Date().toISOString()
  }
};

