for (const item of items) {
  if (item.binary && item.binary.data) {
    item.json.audioBase64 = item.binary.data.data;
    item.json.mimeType = item.binary.data.mimeType || 'audio/ogg';
  }
}
return items;

let telegramData = null;
try { telegramData = $("Telegram Trigger").first().json; } catch (e) { throw new Error('No se pudo obtener datos de Telegram'); }
const voiceFileId = telegramData?.message?.voice?.file_id;
const audioFileId = telegramData?.message?.audio?.file_id;
const fileId = voiceFileId || audioFileId;
if (!fileId) throw new Error('No se encontró file_id de audio');
const chatId = telegramData?.message?.chat?.id || "";
const messageId = telegramData?.message?.message_id || "";
let mimeType = 'audio/ogg';
if (audioFileId) { const audioMime = telegramData?.message?.audio?.mime_type; if (audioMime) mimeType = audioMime; }
return { json: { fileId, mimeType, chatId, messageId, isVoice: !!voiceFileId } };

/**
 * 🔀 XUS CHANNEL NORMALIZER v5.1 — CON AUDIO WA
 */
const items = $input.all();
const results = [];

for (const item of items) {
  let d = item.json;
  if (d.body && typeof d.body === 'object' && (d.body.channel || d.body.type || d.body.from)) {
    d = d.body;
  }

  const isWhatsApp = (
    d.channel === 'whatsapp' ||
    d.type === 'conversation' ||
    d.messageType === 'conversation' ||
    d.messageType === 'audioMessage' ||
    d.messageType === 'pttMessage' ||
    (typeof d.from === 'string' && (d.from.includes('@lid') || d.from.includes('@s.whatsapp.net')))
  );

  if (isWhatsApp) {
    const rawFrom = String(d.from || '');
    const phone = rawFrom.replace(/@.*$/, '');
    const msgId = (d.key && d.key.id) ? d.key.id : ('wa_' + Date.now());
    const name = d.pushName || 'Lead';
    const text = d.text || '';
    const jid = (d.key && d.key.remoteJid) ? d.key.remoteJid : rawFrom;
    const isAudio = d.isAudio === true;

    results.push({
      json: {
        channel: 'whatsapp',
        userPhone: phone,
        userName: name,
        text: text,
        messageId: msgId,
        chatId: phone,
        isGroup: d.isGroup === true,
        remoteJid: jid,
        message: {
          text: text,
          chat: { id: phone },
          message_id: msgId,
          from: { id: phone, first_name: name, username: phone }
        },
        whatsapp: {
          from: rawFrom,
          phone: phone,
          isGroup: d.isGroup === true,
          pushName: name,
          messageType: d.messageType || 'conversation',
          key: { id: msgId, remoteJid: jid },
          isAudio: isAudio,
          audioBase64: d.audioBase64 || null,
          audioMime: d.audioMime || null
        }
      }
    });
  } else {
    results.push({ json: { channel: 'telegram', ...d } });
  }
}
return results;

